export default {
  name: 'Icon',
  props: {
    name: { type: String, required: true },
    size: { type: [Number, String], default: 40 },
    color: { type: String, default: '#1c1b1b' },
    fill: { type: Boolean, default: false }
  },
  computed: {
    sizeNum() {
      return typeof this.size === 'number' ? this.size : Number(this.size)
    },
    wrapperStyle() {
      const s = `${this.sizeNum}rpx`
      return `width:${s};height:${s};display:inline-flex;align-items:center;justify-content:center;vertical-align:middle;flex-shrink:0;`
    },
    imgStyle() {
      const s = `${this.sizeNum}rpx`
      return `width:${s};height:${s};`
    },
    svgUri() {
      const path = PATHS[this.name]
      if (!path) return ''
      const color = encodeURIComponent(this.color)
      const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${this.color}"><path d="${path}"/></svg>`
      return 'data:image/svg+xml;utf8,' + encodeURIComponent(svg).replace(/%20/g, ' ')
    }
  }
}
